:root {
  --bg: #0a1628;
  --bg-elev: #0f1f38;
  --bg-card: rgba(20, 36, 60, 0.78);
  --border: rgba(73, 132, 209, 0.18);
  --border-strong: rgba(73, 132, 209, 0.4);
  --text: #e3edff;
  --muted: #8aa3c7;
  --ts-blue: #3178c6;
  --ts-blue-light: #4f9dde;
  --accent: #61dafb;
  --success: #4ade80;
  --warn: #fbbf24;
  --danger: #f87171;
  --code-bg: rgba(5, 12, 25, 0.85);
  --shadow: 0 30px 60px -20px rgba(0, 0, 0, 0.65);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI',
    Roboto, sans-serif;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  background: var(--bg);
  color: var(--text);
  min-height: 100%;
  -webkit-font-smoothing: antialiased;
}

body {
  background:
    radial-gradient(900px 500px at 100% 0%, rgba(49, 120, 198, 0.32), transparent 60%),
    radial-gradient(800px 500px at 0% 100%, rgba(97, 218, 251, 0.12), transparent 60%),
    var(--bg);
  overflow-x: hidden;
}

.bg-grid {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  background-image:
    linear-gradient(rgba(73, 132, 209, 0.08) 1px, transparent 1px),
    linear-gradient(90deg, rgba(73, 132, 209, 0.08) 1px, transparent 1px);
  background-size: 48px 48px;
  background-position: center;
  mask-image: radial-gradient(ellipse at center, black 30%, transparent 80%);
  -webkit-mask-image: radial-gradient(ellipse at center, black 30%, transparent 80%);
  opacity: 0.55;
}

#app {
  position: relative;
  z-index: 1;
  max-width: 1080px;
  margin: 0 auto;
  padding: 56px 24px 80px;
}

.hero {
  text-align: center;
  margin-bottom: 56px;
}

.badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 14px;
  border: 1px solid var(--border);
  border-radius: 999px;
  background: rgba(20, 36, 60, 0.6);
  backdrop-filter: blur(8px);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 24px;
}

.badge svg { display: block; }

h1 {
  font-size: clamp(2rem, 5vw, 3.4rem);
  line-height: 1.1;
  font-weight: 800;
  margin: 0 0 18px;
  letter-spacing: -0.02em;
}

.gradient-text {
  background: linear-gradient(120deg, var(--ts-blue) 0%, var(--accent) 100%);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  color: transparent;
}

.lede {
  max-width: 640px;
  margin: 0 auto 28px;
  color: var(--muted);
  font-size: 17px;
  line-height: 1.6;
}

.lede code, .card p code, .card h2 code {
  background: var(--code-bg);
  padding: 2px 6px;
  border-radius: 4px;
  color: var(--ts-blue-light);
  font-size: 13px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
}

.hero-actions {
  display: flex;
  gap: 12px;
  justify-content: center;
  flex-wrap: wrap;
}

.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 20px;
  border-radius: 10px;
  border: 1px solid transparent;
  font-family: inherit;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.15s ease, box-shadow 0.15s ease,
    background 0.15s ease;
  text-decoration: none;
  color: var(--text);
  background: rgba(255, 255, 255, 0.05);
  white-space: nowrap;
}

.btn:hover { transform: translateY(-1px); }
.btn:active { transform: translateY(0); }

.btn-primary {
  background: linear-gradient(120deg, var(--ts-blue), var(--accent));
  color: #0a1628;
  box-shadow: 0 12px 30px -10px rgba(49, 120, 198, 0.7);
}

.btn-primary:hover {
  box-shadow: 0 16px 40px -10px rgba(49, 120, 198, 0.9);
}

.btn-ghost {
  background: transparent;
  border-color: var(--border-strong);
  color: var(--text);
}

.btn-ghost:hover { background: rgba(255, 255, 255, 0.05); }

.btn-small { padding: 8px 14px; font-size: 13px; }

.icon { font-size: 12px; }

.grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 20px;
  margin-bottom: 48px;
}

.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 22px;
  backdrop-filter: blur(12px);
  box-shadow: var(--shadow);
  display: flex;
  flex-direction: column;
  gap: 14px;
  transition: transform 0.2s ease, border-color 0.2s ease;
  position: relative;
  overflow: hidden;
}

.card::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg,
    rgba(49, 120, 198, 0.12) 0%, transparent 50%);
  pointer-events: none;
  opacity: 0;
  transition: opacity 0.3s ease;
}

.card:hover {
  transform: translateY(-2px);
  border-color: var(--border-strong);
}
.card:hover::before { opacity: 1; }
.card > * { position: relative; z-index: 1; }

.card header { display: flex; flex-direction: column; gap: 8px; }

.tag {
  align-self: flex-start;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  padding: 4px 10px;
  border-radius: 999px;
  background: rgba(49, 120, 198, 0.18);
  color: var(--ts-blue-light);
}

.card h2 { font-size: 17px; margin: 0; font-weight: 700; }
.card p {
  margin: 0;
  color: var(--muted);
  font-size: 14px;
  line-height: 1.55;
  flex-grow: 1;
}

.code {
  margin: 0;
  padding: 14px 16px;
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  font-family: 'JetBrains Mono', 'Fira Code', ui-monospace, monospace;
  font-size: 12.5px;
  line-height: 1.6;
  color: #d8e3f5;
  overflow-x: auto;
}

.code code { display: block; white-space: pre; }
.code .kw  { color: #c792ea; }
.code .ty  { color: #82aaff; }
.code .str { color: #c3e88d; }
.code .num { color: #f78c6c; }
.code .cmt { color: #5c6c80; font-style: italic; }

.card-action {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
  border-top: 1px dashed var(--border);
  padding-top: 14px;
  margin-top: 4px;
}

output {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12.5px;
  color: var(--muted);
  margin-left: auto;
  padding: 4px 10px;
  border-radius: 6px;
  background: rgba(255, 255, 255, 0.03);
  min-width: 60px;
  text-align: right;
  max-width: 100%;
  overflow: hidden;
  text-overflow: ellipsis;
}

output.success { color: var(--success); }
output.error   { color: var(--danger);  }
output.busy    { color: var(--warn);    }

.console {
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 18px 20px;
  box-shadow: var(--shadow);
}

.console header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.console h3 {
  margin: 0;
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--muted);
}

#console-log {
  list-style: none;
  margin: 0;
  padding: 0;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12.5px;
  line-height: 1.6;
  max-height: 220px;
  overflow-y: auto;
}

#console-log li {
  padding: 4px 0;
  border-bottom: 1px solid rgba(73, 132, 209, 0.08);
  display: flex;
  gap: 10px;
}

#console-log li:last-child { border-bottom: none; }
#console-log .ts {
  color: var(--muted);
  flex-shrink: 0;
}
#console-log .msg { color: var(--text); word-break: break-word; }
#console-log .info .msg { color: var(--ts-blue-light); }
#console-log .ok   .msg { color: var(--success); }
#console-log .err  .msg { color: var(--danger);  }
#console-log .empty {
  color: var(--muted);
  font-style: italic;
  border: none;
}

.foot {
  text-align: center;
  margin-top: 48px;
  color: var(--muted);
  font-size: 13px;
}

.kbd {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  background: rgba(255, 255, 255, 0.06);
  padding: 2px 6px;
  border-radius: 4px;
  border: 1px solid var(--border);
  font-size: 11.5px;
}

@media (max-width: 640px) {
  #app { padding: 32px 16px 56px; }
  .hero { margin-bottom: 36px; }
  .card { padding: 18px; }
}

/**
 * TypeScript + Webpack Playground
 * -------------------------------
 * Each demo highlights one feature of the type system. Open
 * src/types.ts to see the shared definitions, then edit any demo
 * — ts-loader rebuilds and you'll see compile errors immediately.
 */
import {
  type User,
  type Result,
  type UserId,
  type PostId,
  userId,
  postId,
} from './types';

// --- Generics --------------------------------------------------------------
function last<T>(arr: readonly T[]): T | undefined {
  return arr[arr.length - 1];
}

// --- Discriminated unions --------------------------------------------------
function attempt(): Result<number> {
  const success = Math.random() > 0.4;
  return success
    ? { kind: 'ok',    value: Math.floor(Math.random() * 100) }
    : { kind: 'error', reason: 'Network unreachable' };
}

function describeResult(r: Result<number>): string {
  // Switch on the discriminant — TS narrows each branch automatically.
  switch (r.kind) {
    case 'ok':    return `OK · value=${r.value}`;
    case 'error': return `ERR · ${r.reason}`;
  }
}

// --- Narrowing -------------------------------------------------------------
function describe(x: string | number | null): string {
  if (x === null)            return 'null';
  if (typeof x === 'string') return `str("${x.toUpperCase()}")`;
  return `num(${x.toFixed(2)})`;
}

// --- Utility types ---------------------------------------------------------
type DraftUser   = Partial<User>;
type UserPreview = Pick<User, 'id' | 'name' | 'role'>;
type WithoutId   = Omit<User, 'id'>;

function toPreview(u: User): UserPreview {
  return { id: u.id, name: u.name, role: u.role };
}

// --- Readonly --------------------------------------------------------------
function sum(xs: readonly number[]): number {
  return xs.reduce((a, b) => a + b, 0);
}

// --- Branded IDs -----------------------------------------------------------
function fetchUser(_id: UserId): string { return `User<${_id}>`; }
function fetchPost(_id: PostId): string { return `Post<${_id}>`; }

// --- Wiring ---------------------------------------------------------------
const log = createConsole(document.getElementById('console-log')!);

const demos: Record<string, () => string> = {
  generics: () => {
    const nums    = [3, 1, 4, 1, 5, 9, 2, 6];
    const words   = ['type', 'safe', 'always'];
    const lastNum  = last(nums);
    const lastWord = last(words);
    log.info(`last(numbers) → ${lastNum} (type: number)`);
    log.info(`last(strings) → "${lastWord}" (type: string)`);
    return `${lastNum} · "${lastWord}"`;
  },

  union: () => {
    const r = attempt();
    const text = describeResult(r);
    if (r.kind === 'ok') log.ok(text);
    else                 log.err(text);
    return text;
  },

  narrow: () => {
    const samples: (string | number | null)[] = ['typescript', 3.14159, null, 42, 'narrow'];
    const out = samples.map(describe);
    out.forEach((line) => log.info(line));
    return `${samples.length} values`;
  },

  utility: () => {
    const ada: User = {
      id: 1,
      name: 'Ada Lovelace',
      email: 'ada@analytical.engine',
      role: 'admin',
      active: true,
    };
    const draft: DraftUser     = { name: 'Anon' };
    const preview: UserPreview = toPreview(ada);
    const { id: _id, ...noId } = ada;
    const omitted: WithoutId   = noId;

    log.info(`Partial → ${JSON.stringify(draft)}`);
    log.info(`Pick    → ${JSON.stringify(preview)}`);
    log.info(`Omit    → ${JSON.stringify(omitted)}`);
    return `${preview.name}`;
  },

  readonly: () => {
    const xs: readonly number[] = Array.from({ length: 10 }, (_, i) => i + 1);
    const total = sum(xs);
    log.info(`Σ [${xs.join(', ')}] = ${total}`);
    return String(total);
  },

  brand: () => {
    const u = userId('u_42');
    const p = postId('p_99');
    log.info(`fetchUser(u) → ${fetchUser(u)}`);
    log.info(`fetchPost(p) → ${fetchPost(p)}`);
    log.info('Try swapping them — tsc would reject it at compile time.');
    return 'compile-time only';
  },
};

document.addEventListener('click', async (event) => {
  const target = event.target as HTMLElement;
  const demoBtn = target.closest<HTMLElement>('[data-demo]');
  if (demoBtn) return runDemo(demoBtn.dataset.demo!);

  const action = target.closest<HTMLElement>('[data-action]')?.dataset.action;
  if (action === 'run-all') {
    log.clear();
    log.info('Running every demo…');
    for (const key of Object.keys(demos)) {
      await runDemo(key);
      await wait(150);
    }
    log.ok('Done.');
  }
  if (action === 'clear') log.clear();
});

function runDemo(key: string): Promise<void> {
  const handler = demos[key];
  if (!handler) return Promise.resolve();
  setOutput(key, 'running…', 'busy');
  try {
    const result = handler();
    setOutput(key, result, 'success');
  } catch (err) {
    log.err((err as Error).message);
    setOutput(key, 'failed', 'error');
  }
  return Promise.resolve();
}

function setOutput(key: string, text: string, state: '' | 'busy' | 'success' | 'error' = ''): void {
  const el = document.querySelector(`[data-output="${key}"]`);
  if (!el) return;
  el.textContent = text;
  el.className = state;
}

interface Logger {
  info: (msg: string) => void;
  ok:   (msg: string) => void;
  err:  (msg: string) => void;
  clear: () => void;
}

const MAX_LOG_ENTRIES = 50;

function createConsole(root: HTMLElement): Logger {
  const emptyState = (): HTMLLIElement => {
    const li = document.createElement('li');
    li.className = 'empty';
    li.textContent = 'tsc is quiet. Click a demo above.';
    return li;
  };
  root.appendChild(emptyState());

  function append(kind: 'info' | 'ok' | 'err', msg: string): void {
    const first = root.firstElementChild;
    if (first && first.classList.contains('empty')) root.innerHTML = '';
    const li = document.createElement('li');
    li.className = kind;
    li.innerHTML = `<span class="ts"></span><span class="msg"></span>`;
    li.querySelector<HTMLSpanElement>('.ts')!.textContent =
      new Date().toLocaleTimeString([], { hour12: false });
    li.querySelector<HTMLSpanElement>('.msg')!.textContent = msg;
    root.appendChild(li);
    while (root.children.length > MAX_LOG_ENTRIES) {
      root.removeChild(root.firstElementChild!);
    }
    root.scrollTop = root.scrollHeight;
  }

  return {
    info: (m) => append('info', m),
    ok:   (m) => append('ok',   m),
    err:  (m) => append('err',  m),
    clear: () => { root.innerHTML = ''; root.appendChild(emptyState()); },
  };
}

const wait = (ms: number): Promise<void> =>
  new Promise((resolve) => setTimeout(resolve, ms));

log.info('TypeScript ready. Click any demo card to begin.');

/**
 * Shared types for the playground.
 * --------------------------------
 * Keeping types in their own module lets ts-loader treat them as
 * erasable — they cost zero bytes in the bundle.
 */

export interface User {
  id: number;
  name: string;
  email: string;
  role: 'admin' | 'editor' | 'viewer';
  active: boolean;
}

// Discriminated union: TS forces you to check `kind` before
// touching `.value` or `.reason`.
export type Result<T> =
  | { kind: 'ok';    value: T }
  | { kind: 'error'; reason: string };

// Branded primitives — same runtime type as `string`, distinct at
// compile time. Mixing UserId and PostId becomes an error.
export type UserId = string & { readonly __brand: 'UserId' };
export type PostId = string & { readonly __brand: 'PostId' };

export const userId = (s: string): UserId => s as UserId;
export const postId = (s: string): PostId => s as PostId;

const webpack = require('webpack');
const path = require('path');

const config = {
  mode: 'development',
  entry: './src/index.ts',
  output: {
    path: path.resolve(__dirname, 'dist'),
    filename: 'bundle.js'
  },
  resolve: {
    modules:[
      'node_modules',
      path.join(process.env.NPM_CONFIG_PREFIX || __dirname, 'lib/node_modules')
    ],
    extensions: [
      '.tsx',
      '.ts',
      '.js'
    ]
  },
  resolveLoader: {
    modules:[
      'node_modules',
      path.join(process.env.NPM_CONFIG_PREFIX || __dirname, 'lib/node_modules')
    ]
  },
  module: {
    rules: [
      {
        test: /\.ts(x)?$/,
        loader: 'ts-loader',
        exclude: /node_modules|cdn_modules/
      }
    ]
  },
  devServer: {
    port: 9950,
    static: {
      directory: './dist'
    }
  }
};

module.exports = config;
